#!/usr/bin/env node
/**
 * Generate the COMMITTED component-type-location baseline (AE-0144).
 *
 * Reproducible command:
 *   npm run component-types:baseline
 *
 * Writes `scripts/component-type-location-baseline.json` capturing:
 *   - `count`: number of grandfathered inline component/hook type declarations
 *     (the ratchet ceiling — lint fails if violations exceed this)
 *   - `allowlist`: stable `<file>::<kind>::<name>` keys for each grandfathered
 *     declaration
 *   - `violations`: human-readable detail for review/auditing
 *
 * This file is generated, never hand-edited. Re-run after refactors move inline
 * types into a colocated `types.ts` to RATCHET THE COUNT DOWN (it must only ever
 * shrink). See `component-type-location.config.mjs` for the convention.
 */

import { writeFileSync } from "node:fs";

import { BASELINE_PATH } from "./component-type-location.config.mjs";
import {
  scanInlineComponentTypes,
  violationKey,
} from "./component-type-location-scan.mjs";

function main() {
  const violations = scanInlineComponentTypes();
  const allowlist = [...new Set(violations.map(violationKey))].sort();

  const baseline = {
    $comment:
      "GENERATED by scripts/generate-component-type-location-baseline.mjs (npm run component-types:baseline). Do not hand-edit. AE-0144 component-type-location ratchet (down-only).",
    count: allowlist.length,
    allowlist,
    violations: violations.map((violation) => ({
      file: violation.file,
      kind: violation.kind,
      name: violation.name,
    })),
  };

  writeFileSync(
    BASELINE_PATH,
    `${JSON.stringify(baseline, null, 2)}\n`,
    "utf8",
  );
  process.stdout.write(
    `Wrote ${BASELINE_PATH} with ${baseline.count} grandfathered inline ` +
      `component/hook type declaration(s).\n`,
  );
}

main();
